. "$PSScriptRoot\..\Common.ps1"
try{ Require-Admin; $p='HKLM:\SYSTEM\CurrentControlSet\Services\LanmanServer\Parameters'; New-Item -Path $p -Force|Out-Null; New-ItemProperty -Path $p -Name AutoShareWks -Value 0 -PropertyType DWord -Force|Out-Null; Get-SmbShare -ErrorAction SilentlyContinue|Where-Object {$_.Name -match '^[A-Z]\$$'}|ForEach-Object{Remove-SmbShare -Name $_.Name -Force -ErrorAction SilentlyContinue}; New-Result -Step '03_DisableAdminShares' -Enabled $true -Status '已持久禁止 C$/D$ 等盘符默认管理共享；ADMIN$/IPC$ 可能仍由系统维护' -Evidence @{AutoShareWks=0} }catch{ New-Result -Step '03_DisableAdminShares' -Success $false -Status '启用失败' -ErrorMessage $_.Exception.Message }